import { mathMin } from '../../../core/zc-constants';
import { pick, invokeFunction, perToPx } from '../../../utils/zcutils';
import { ALLOWED_OPERATORS } from '../allowed-operators';
import { ScaleRegistry } from '../../scale-registry';

export function baseSize(operatorC, appliedOperators) {
    let { config = {}, size: _defaultSize, callbackArgs = [], correction } = operatorC,
        minSize = invokeFunction(config.minSize, ...callbackArgs),
        maxSize = invokeFunction(config.maxSize, ...callbackArgs);

    let defaultSize = [pick(minSize, _defaultSize[0]), pick(maxSize, _defaultSize[1])].map(convertTo(operatorC));
    return correction ? correction(defaultSize) : defaultSize;
}

export function userRanges(operatorC, appliedOperators) {
    let { size, callbackArgs = [] } = operatorC,
        userSizes = invokeFunction(size, ...callbackArgs);

    return userSizes.map(convertTo(operatorC));
}

function convertTo(operatorC) {
    let { plotBound } = operatorC,
        dimension = plotBound ? mathMin(plotBound.width, plotBound.height) : 1;
    return _ => perToPx(_, dimension);
}

ALLOWED_OPERATORS.set('baseSize', baseSize);
ALLOWED_OPERATORS.set('userRanges', userRanges);

ScaleRegistry.add('size.baseSize', baseSize);
ScaleRegistry.add('size.userRanges', userRanges);
